// Para un rubro dado, devuelve el promedio y umbrales relativos para clasificar
// (usado por la tabla comparativa para colorear celdas según nivel relativo al rubro)
function umbralesDelRubro(key){
  const vals = M_ALIC.map(m => aliVal(m, key)).filter(v => v != null);
  if(vals.length === 0) return null;
  const avg = vals.reduce((s,v)=>s+v,0) / vals.length;
  const u1 = avg * 0.75;  // < u1 → Baja
  const u2 = avg;         // u1–u2 → Media
  const u3 = avg * 1.25;  // u2–u3 → Media-alta, > u3 → Alta
  return {avg, u1, u2, u3};
}
// Devuelve el índice de zona (0-3) para un valor dado, según umbrales del rubro
function zonaDeValor(v, u){
  if(v < u.u1) return 0;
  if(v < u.u2) return 1;
  if(v < u.u3) return 2;
  return 3;
}
// Helper: nombre completo de municipio con chip TDF si corresponde, sin badge
