function buildPresTable(){
  let munis = DATA.filter(m => m.indice_fiscal);
  // Aplicar sort si está activo, sino default por total asc (puesto 1° = menor carga tributaria)
  if(sortState['tbody-pres']){
    munis = applySort(munis, 'tbody-pres', (m, col) => {
      const idx = m.indice_fiscal;
      if(col === 'nombre') return m.nombre;
      if(col === 'indice') return idx.total; // "Puesto" ordena por índice
      if(col === 'cuartil') return idx.cuartil; // Q1, Q2, Q3, Q4 ordena alfabéticamente
      return idx[col];
    });
  } else {
    munis = munis.slice().sort((a,b) => a.indice_fiscal.total - b.indice_fiscal.total);
  }
  
  // Actualizar indicadores en headers
  const headers = {
    'th-pres-puesto':'Puesto', 'th-pres-muni':'Municipio',
    'th-pres-suma':'Promedio 5 rubros', 'th-pres-total':'Presión Fiscal',
  };
  const headers_sub = {
    'th-pres-cuartil':['Grupo',''],
    'th-pres-z':['Distancia al','promedio']
  };
  const cols = {'th-pres-puesto':'indice','th-pres-muni':'nombre','th-pres-suma':'promedio_alic','th-pres-total':'total','th-pres-cuartil':'cuartil','th-pres-z':'zscore'};
  for(const [id, label] of Object.entries(headers)){
    const th = document.getElementById(id);
    if(th) th.innerHTML = label + sortInd('tbody-pres', cols[id]);
  }
  for(const [id, [label, sub]] of Object.entries(headers_sub)){
    const th = document.getElementById(id);
    if(th) th.innerHTML = label + sortInd('tbody-pres', cols[id]) + (sub ? '<br><span style="font-size:9px;color:var(--tx-sec);font-weight:400">'+sub+'</span>' : '');
  }
  
  // Calcular el puesto "real" según el índice (ordenamiento por total asc) — no por la columna en uso
  const ranking = DATA.filter(m => m.indice_fiscal).slice().sort((a,b) => a.indice_fiscal.total - b.indice_fiscal.total);
  const puestos = {};
  ranking.forEach((m,i) => { puestos[m.nombre] = i+1; });
  
  document.getElementById('tbody-pres').innerHTML = munis.map(m => {
    const idx = m.indice_fiscal;
    const isTdf = m.nombre === 'Tres de Febrero';
    const rowStyle = isTdf ? 'background:#fffdf5;font-weight:600' : '';
    const tvCell = idx.tiene_tv ? '<span style="color:var(--ok);font-weight:600">+0.14</span>' : '<span style="color:var(--tx-sec)">—</span>';
    const habCell = idx.tiene_hab ? '<span style="color:var(--ok);font-weight:600">+0.14</span>' : '<span style="color:var(--tx-sec)">—</span>';
    return `<tr style="${rowStyle}">
      <td style="font-weight:600">${puestos[m.nombre]}°</td>
      <td>${m.nombre}${isTdf ? '<span style="background:var(--gold);color:var(--navy);font-size:9px;font-weight:700;padding:2px 5px;border-radius:4px;margin-left:6px">3F</span>' : ''}</td>
      <td class="r">${trunc2(idx.promedio_alic)}%</td>
      <td class="r">${tvCell}</td>
      <td class="r">${habCell}</td>
      <td class="r" style="font-weight:700">${trunc2(idx.total)}%</td>
      <td class="r"><span style="background:${cuartilColor(idx.cuartil)}22;color:${cuartilColor(idx.cuartil)};padding:2px 8px;border-radius:10px;font-size:10px;font-weight:700">${cuartilLabel(idx.cuartil)}</span></td>
      <td class="r">${idx.zscore>=0?'+':''}${idx.zscore.toFixed(2)}</td>
    </tr>`;
  }).join('');
}

function drawPresChart(){
  const canvas = document.getElementById('presChart');
  if(!canvas) return;
  const munis = DATA.filter(m => m.indice_fiscal).slice().sort((a,b) => a.indice_fiscal.total - b.indice_fiscal.total);
  const N = munis.length;
  const rowH = 22;
  const margL = 140, margR = 60, margT = 20, margB = 30;
  const W = Math.max(680, canvas.parentElement.offsetWidth - 20);
  const H = margT + margB + N*rowH;
  canvas.width = W * 2; canvas.height = H * 2;
  canvas.style.width = W + 'px'; canvas.style.height = H + 'px';
  const ctx = canvas.getContext('2d');
  ctx.scale(2, 2);
  ctx.clearRect(0,0,W,H);
  
  const maxIdx = INDEX_STATS.max;
  const plotW = W - margL - margR;
  const xScale = v => margL + (v/maxIdx) * plotW;
  
  // Línea de mediana
  const medX = xScale(INDEX_STATS.mediana);
  ctx.setLineDash([4, 4]);
  ctx.strokeStyle = '#1e2d5a';
  ctx.lineWidth = 1.5;
  ctx.beginPath();
  ctx.moveTo(medX, margT);
  ctx.lineTo(medX, H - margB);
  ctx.stroke();
  ctx.setLineDash([]);
  
  // Etiqueta mediana
  ctx.fillStyle = '#1e2d5a';
  ctx.font = 'bold 10px Inter, sans-serif';
  ctx.textAlign = 'center';
  ctx.fillText(`Promedio: ${INDEX_STATS.mediana.toFixed(2)}%`, medX, margT - 6);
  
  // Barras
  munis.forEach((m, i) => {
    const y = margT + i*rowH + 2;
    const idx = m.indice_fiscal;
    const barW = (idx.total/maxIdx) * plotW;
    const color = cuartilColor(idx.cuartil);
    const isTdf = m.nombre === 'Tres de Febrero';
    
    // Barra
    ctx.fillStyle = color;
    ctx.fillRect(margL, y, barW, rowH - 4);
    
    // Borde dorado para TDF
    if(isTdf){
      ctx.strokeStyle = '#f0a500';
      ctx.lineWidth = 2;
      ctx.strokeRect(margL, y, barW, rowH - 4);
    }
    
    // Nombre municipio (izq)
    ctx.fillStyle = isTdf ? '#1e2d5a' : '#262626';
    ctx.font = isTdf ? 'bold 10px Inter, sans-serif' : '10px Inter, sans-serif';
    ctx.textAlign = 'right';
    const nombre = (i+1) + '. ' + m.nombre;
    ctx.fillText(nombre.length > 22 ? nombre.substring(0, 21) + '…' : nombre, margL - 6, y + rowH/2);
    
    // Valor (al final de la barra)
    ctx.fillStyle = '#262626';
    ctx.font = 'bold 9px Inter, sans-serif';
    ctx.textAlign = 'left';
    ctx.fillText(trunc2(idx.total) + '%', margL + barW + 4, y + rowH/2);
  });
  
  // Eje X
  ctx.strokeStyle = '#ccc';
  ctx.lineWidth = 0.5;
  ctx.beginPath();
  ctx.moveTo(margL, H - margB);
  ctx.lineTo(margL + plotW, H - margB);
  ctx.stroke();
  ctx.fillStyle = '#666';
  ctx.font = '9px Inter, sans-serif';
  ctx.textAlign = 'center';
  for(let i=0; i<=4; i++){
    const v = (maxIdx/4) * i;
    const x = xScale(v);
    ctx.fillText(v.toFixed(1) + '%', x, H - 14);
    ctx.beginPath();
    ctx.moveTo(x, H - margB);
    ctx.lineTo(x, H - margB + 3);
    ctx.stroke();
  }
}

// ── FISCAL ──────────────────────────────────────────────────────────────────
function populateMuniSels(){
  // Inicializar selector de municipios (chips multi-select)
  buildFisMuniSelector();
  renderFisChips();
}

// Conjuntos para distinguir indicadores — v2 nominal fix
const IND_PCT = ['bu_it','bu_gt','gp_it','gp_gt'];
const IND_GK  = ['gk'];   // ratio de gasto capital / personal (no es %, ni $ absoluto)
const IND_ABS = ['it','gt','rf'];
const IND_LABELS = {
  bu_it:'Inversión sobre ingresos', bu_gt:'Inversión sobre gastos',
  gp_it:'Personal sobre ingresos', gp_gt:'Personal sobre gastos',
  gk:'G.Cap./Personal',
  it:'Ingreso Total', gt:'Gasto Total', rf:'Resultado Financiero'
};


// Estado: municipios seleccionados para Evolución (multi-select)
let fisMunisSelected = ['Tres de Febrero'];

const MUNI_COLORS = ['#f0a500', '#1F7A3F', '#C53030', '#4A6FAA', '#E89547', '#6D5BBA', '#A1887F', '#5DCAA5', '#D946EF', '#0EA5E9', '#84CC16', '#F472B6'];

function buildFisMuniSelector(){
  const sel = document.getElementById('add-muni-fis');
  if(!sel) return;
  // Lista alfabética (incluye TDF) excluyendo los ya seleccionados; filtra por sección si aplica
  let list = DATA.slice().filter(m => m.indices && !fisMunisSelected.includes(m.nombre));
  if(typeof fisFilter !== 'undefined' && fisFilter.startsWith('s')){
    const secNum = parseInt(fisFilter.slice(1));
    list = list.filter(m => m.seccion === secNum);
  }
  list.sort((a,b) => a.nombre.localeCompare(b.nombre,'es'));
  const opts = ['<option value="">+ Agregar municipio…</option>'];
  list.forEach(m => {
    const sec = m.seccion ? ` (S${m.seccion}°)` : '';
    opts.push(`<option value="${m.nombre}">${m.nombre}${sec}</option>`);
  });
  sel.innerHTML = opts.join('');
}

let fisFilter = 'all';

function setFisFilter(f){
  fisFilter = f;
  ['all','s1','s2','s3','s4','s5','s6','s7','s8'].forEach(x => {
    const el = document.getElementById('fis-f-'+x);
    if(el) el.className = 'fbtn';
  });
  const active = document.getElementById('fis-f-'+f);
  if(active) active.className = 'fbtn fa';
  if(f.startsWith('s')){
    const secNum = parseInt(f.slice(1));
    fisMunisSelected = DATA
      .filter(m => m.indices && m.seccion === secNum)
      .map(m => m.nombre);
  }
  buildFisMuniSelector();
  renderFisChips();
  drawFisChart();
  buildFisRanks();
}

function renderFisChips(){
  const cont = document.getElementById('fis-munis-chips');
  if(!cont) return;
  const chips = [];
  fisMunisSelected.forEach((nombre, idx) => {
    const isTdf = nombre === 'Tres de Febrero';
    const color = isTdf ? '#1e2d5a' : MUNI_COLORS[idx % MUNI_COLORS.length];
    const star = isTdf ? ' ⭐' : '';
    chips.push(`<span style="display:inline-flex;align-items:center;gap:4px;background:${color};color:#fff;font-size:10.5px;font-weight:600;padding:3px 4px 3px 8px;border-radius:12px">${nombre}${star}<button onclick="removeFisMuni('${nombre.replace(/'/g,"\\'")}')" style="background:rgba(255,255,255,.3);border:none;color:#fff;width:16px;height:16px;border-radius:50%;cursor:pointer;font-size:11px;line-height:1;display:flex;align-items:center;justify-content:center;padding:0">×</button></span>`);
  });
  if(chips.length === 0){
    cont.innerHTML = '<span style="color:var(--tx-sec);font-style:italic;font-size:10.5px">Sin municipios seleccionados — agregá uno desde el selector arriba</span>';
  } else {
    cont.innerHTML = chips.join('');
  }
}

function addFisMuni(){
  const sel = document.getElementById('add-muni-fis');
  if(!sel || !sel.value) return;
  if(!fisMunisSelected.includes(sel.value)) fisMunisSelected.push(sel.value);
  sel.value = '';
  buildFisMuniSelector();
  renderFisChips();
  drawFisChart();
}

function removeFisMuni(nombre){
  fisMunisSelected = fisMunisSelected.filter(n => n !== nombre);
  buildFisMuniSelector();
  renderFisChips();
  drawFisChart();
}

function clearFisMunis(){
  fisMunisSelected = [];
  buildFisMuniSelector();
  renderFisChips();
  drawFisChart();
}

// Lee los indicadores seleccionados (checkboxes)
function getFisSelectedInd(){
  const cbs = document.querySelectorAll('#fis-ind-checkboxes input[type=checkbox]:checked');
  return Array.from(cbs).map(cb => cb.value);
}
function onFisIndChange(){
  drawFisChart();
  buildFisRanks();
}
// Colores por indicador (los mismos del HTML de los checkboxes)
const FIS_IND_COLORS = {
  bu_it: '#1e2d5a', bu_gt: '#f0a500', gp_it: '#1F7A3F', gp_gt: '#C53030',
  gk: '#7B5EA7',
  it: '#4A6FAA', gt: '#E89547', rf: '#6D5BBA'
};

function drawFisChart(){
  // 1) Indicadores seleccionados
  let keys = getFisSelectedInd();
  if(keys.length === 0) keys = ['bu_it'];

  // 2) Filtrar por tipo: gk es un tipo propio (ratio, ni % ni $)
  // Tipos: 'pct' (bu_*,gp_*), 'gk' (ratio), 'abs' ($)
  function indType(k){ if(IND_PCT.includes(k)) return 'pct'; if(IND_GK.includes(k)) return 'gk'; return 'abs'; }
  const firstType = indType(keys[0]);
  const keysSameType = keys.filter(k => indType(k) === firstType);
  const warn = document.getElementById('fis-ind-warn');
  if(warn) warn.style.display = (keysSameType.length < keys.length) ? 'block' : 'none';
  keys = keysSameType;
  const isPct = firstType === 'pct';
  const isGK  = firstType === 'gk';

  // 3) Municipios seleccionados (TDF primero)
  let munis = fisMunisSelected.slice();
  const munisData = munis.map(n => DATA.find(x => x.nombre === n)).filter(m => m && m.indices);

  // 4) Construir series: M × I combinaciones
  const allSeries = [];
  munisData.forEach(m => {
    keys.forEach(k => {
      let seriesData;
      if(isGK){
        // gk viene de m.var.gk.b (array de 3 años)
        if(!m.var || !m.var.gk || !m.var.gk.b) return;
        seriesData = m.var.gk.b.map(v => v == null ? null : v);
      } else {
        if(!m.indices[k]) return;
        // it/gt/rf usan valores nominales (.n); los ratios usan .b
        const src = IND_ABS.includes(k) ? m.indices[k].n : m.indices[k].b;
        if(!src) return;
        seriesData = src.map(v => v==null ? null : (isPct ? v*100 : v/1000000));
      }
      if(seriesData.some(v => v !== null)){
        allSeries.push({ muni: m.nombre, key: k, data: seriesData });
      }
    });
  });

  const c = document.getElementById('chart-fis');
  const W = c.parentElement.offsetWidth - 28, H = 260;
  c.width = W; c.height = H;
  const ctx = c.getContext('2d');
  ctx.clearRect(0,0,W,H);

  if(allSeries.length === 0){
    ctx.font='14px Inter'; ctx.fillStyle='#999'; ctx.textAlign='center';
    ctx.fillText('Sin datos para esta combinación de municipios e indicadores', W/2, H/2);
    document.getElementById('chart-fis-leg').innerHTML = '';
    return;
  }

  const pad = {t:20,r:30,b:36,l:75};
  const cw = W-pad.l-pad.r, ch = H-pad.t-pad.b;
  const allValsFlat = allSeries.flatMap(s => s.data.filter(v => v!=null));
  const minV = Math.min(...allValsFlat, 0);
  const maxV = Math.max(...allValsFlat, 0);
  const rng = (maxV - minV) || 1;
  const yMin = minV - rng*0.15, yMax = maxV + rng*0.15;

  ctx.strokeStyle = '#ccc'; ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(pad.l, pad.t); ctx.lineTo(pad.l, H-pad.b);
  ctx.moveTo(pad.l, H-pad.b); ctx.lineTo(W-pad.r, H-pad.b);
  ctx.stroke();

  const y0 = H-pad.b - (0 - yMin)/(yMax - yMin) * ch;
  if(y0 > pad.t && y0 < H-pad.b){
    ctx.strokeStyle = '#aaa'; ctx.setLineDash([3,3]);
    ctx.beginPath(); ctx.moveTo(pad.l, y0); ctx.lineTo(W-pad.r, y0); ctx.stroke();
    ctx.setLineDash([]);
  }
  ctx.fillStyle = '#888'; ctx.font = '10px Inter'; ctx.textAlign = 'right';
  [yMin, (yMin+yMax)/2, yMax].forEach(v => {
    const y = H-pad.b - (v - yMin)/(yMax - yMin) * ch;
    const lbl = isPct ? trunc1(v)+'%' : isGK ? trunc2(v*100)+'%' : '$'+Math.trunc(v).toLocaleString('es-AR')+' M';
    ctx.fillText(lbl, pad.l-5, y+3);
  });
  ctx.textAlign = 'center';
  YRS.forEach((y,i) => {
    const x = pad.l + (i/2)*cw;
    ctx.fillText(y, x, H-pad.b+18);
  });

  // Estrategia de color:
  //   - 1 muni, varios indicadores → color por INDICADOR
  //   - varios munis, 1 indicador → color por MUNI (TDF=navy)
  //   - varios munis × varios indicadores → color por muni, dash distinto por indicador
  const oneMuni = munisData.length === 1;
  const oneInd = keys.length === 1;
  // Patrones de dash por indicador para distinguir cuando hay varios ind
  const dashPatterns = [[], [6,3], [2,3], [8,3,2,3], [10,2,2,2], [4,2,4,8], [12,3]];

  allSeries.forEach((s, idx) => {
    const isTdf = s.muni === 'Tres de Febrero';
    // Color
    let finalColor;
    if(oneInd){
      finalColor = isTdf ? '#1e2d5a' : MUNI_COLORS[(munisData.findIndex(m=>m.nombre===s.muni)) % MUNI_COLORS.length];
    } else if(oneMuni){
      finalColor = FIS_IND_COLORS[s.key] || '#1e2d5a';
    } else {
      // Mix: color por muni, dash por indicador
      finalColor = isTdf ? '#1e2d5a' : MUNI_COLORS[(munisData.findIndex(m=>m.nombre===s.muni)) % MUNI_COLORS.length];
    }
    const lineWidth = isTdf ? 3 : 2.2;
    // Dash
    let dash = [];
    if(!oneInd && !oneMuni){
      dash = dashPatterns[keys.indexOf(s.key) % dashPatterns.length];
    }
    ctx.strokeStyle = finalColor; ctx.lineWidth = lineWidth;
    ctx.setLineDash(dash);
    ctx.beginPath();
    let started = false;
    s.data.forEach((v,i) => {
      if(v == null) return;
      const x = pad.l + (i/2)*cw;
      const y = H-pad.b - (v - yMin)/(yMax - yMin) * ch;
      if(!started){ ctx.moveTo(x,y); started = true; }
      else ctx.lineTo(x,y);
    });
    ctx.stroke();
    ctx.setLineDash([]);
    // Puntos
    s.data.forEach((v,i) => {
      if(v == null) return;
      const x = pad.l + (i/2)*cw;
      const y = H-pad.b - (v - yMin)/(yMax - yMin) * ch;
      ctx.fillStyle = finalColor;
      ctx.beginPath(); ctx.arc(x,y,isTdf?5:4,0,Math.PI*2); ctx.fill();
    });
    // Etiquetas: solo si hay 1 serie (1 muni × 1 ind) para no saturar
    if(allSeries.length === 1){
      s.data.forEach((v,i) => {
        if(v == null) return;
        const x = pad.l + (i/2)*cw;
        const y = H-pad.b - (v - yMin)/(yMax - yMin) * ch;
        ctx.font = 'bold 10px Inter'; ctx.textAlign = 'center';
        const lbl = isPct ? trunc1(v)+'%' : isGK ? trunc2(v*100)+'%' : '$'+Math.trunc(v).toLocaleString('es-AR') + ' M';
        ctx.strokeStyle = '#fff'; ctx.lineWidth = 3; ctx.strokeText(lbl, x, y - 10);
        ctx.fillStyle = finalColor; ctx.fillText(lbl, x, y - 10);
      });
    }
  });

  // Leyenda
  const legHtml = allSeries.map(s => {
    const isTdf = s.muni === 'Tres de Febrero';
    let color;
    if(oneInd){
      color = isTdf ? '#1e2d5a' : MUNI_COLORS[(munisData.findIndex(m=>m.nombre===s.muni)) % MUNI_COLORS.length];
    } else if(oneMuni){
      color = FIS_IND_COLORS[s.key] || '#1e2d5a';
    } else {
      color = isTdf ? '#1e2d5a' : MUNI_COLORS[(munisData.findIndex(m=>m.nombre===s.muni)) % MUNI_COLORS.length];
    }
    let label;
    if(oneMuni) label = IND_LABELS[s.key];
    else if(oneInd) label = s.muni + (isTdf ? ' ⭐' : '');
    else label = s.muni + (isTdf ? ' ⭐' : '') + ' · ' + IND_LABELS[s.key];
    return `<span style="margin-right:14px;font-weight:${isTdf?'700':'500'};font-size:11px"><span class="lg-dot" style="background:${color}"></span>${label}</span>`;
  }).join('');
  document.getElementById('chart-fis-leg').innerHTML = legHtml;

  // Posición: solo con 1 muni y 1 indicador
  if(munisData.length === 1 && keys.length === 1){
    const m = munisData[0], k = keys[0];
    const v25 = v2025(m, k);
    if(v25 != null){
      const valid = M_FISCAL.map(x => v2025(x,k)).filter(v => v!=null);
      const sorted = [...valid].sort((a,b) => b-a);
      const pos = sorted.indexOf(v25) + 1;
      document.getElementById('chart-fis-leg').innerHTML += `<span style="margin-left:auto"><span class="pos-pill">Posición ${pos} de ${valid.length}: ${m.nombre}</span></span>`;
    }
  }
}

function buildFisRanks(){
  let keys = getFisSelectedInd();
  if(keys.length === 0) keys = ['bu_it'];
  const key = keys[0];
  const isPct = IND_PCT.includes(key);
  const isGK  = IND_GK.includes(key);
  // En porcentajes mayor=mejor para BU/* (más inversión), y conceptualmente personal alto no es ni mejor ni peor → orden descendente por valor.
  // En cifras absolutas, mayor cifra = primero. RF positivo = mejor.
  const valid = M_FISCAL.map(m => ({m, v:v2025(m,key)})).filter(x => x.v != null);
  valid.sort((a,b) => b.v - a.v);
  document.getElementById('top10-t').innerHTML = `Top 10 — Mayor ${IND_LABELS[key]} 2025`;
  document.getElementById('bot10-t').innerHTML = `Top 10 — Menor ${IND_LABELS[key]} 2025`;
  function fmt(v){
    if(isPct) return pct2Raw(v);
    if(isGK)  return trunc2(v*100)+'%';
    if(key==='rf' && v<0) return '<span style="color:var(--bad)">−$'+Math.trunc(-v/1000000).toLocaleString('es-AR')+' M</span>';
    return '$'+Math.trunc(v/1000000).toLocaleString('es-AR')+' M';
  }
  function rankRow(x, i, badRank){
    const tipo = badRank ? 'worst' : 'best';
    const colCls = (isPct||isGK) ? (x.v>0?'var(--ok)':'var(--bad)') : (key==='rf' ? (x.v>=0?'var(--ok)':'var(--bad)') : 'var(--tx-pri)');
    return `<div style="display:flex;align-items:center;gap:7px;padding:5px 0;border-bottom:.5px solid var(--bd-3)">
      ${rankBadge(i, tipo, 20)}
      <div style="flex:1;font-size:12px;font-weight:500">${x.m.nombre}${tdfChip(x.m)}${muniBadge(x.m)}</div>
      <span style="min-width:80px;text-align:right;font-size:11px;font-weight:600;color:${colCls};font-variant-numeric:tabular-nums">${fmt(x.v)}</span>
    </div>`;
  }
  document.getElementById('rank-fis-top').innerHTML = valid.slice(0,10).map((x,i) => rankRow(x,i,false)).join('');
  document.getElementById('rank-fis-bot').innerHTML = valid.slice(-10).reverse().map((x,i) => rankRow(x,i,true)).join('');
}

let filtroF = 'all';
function filtF(f){
  filtroF = f;
  ['all','pos','neg'].forEach(x => { const el = document.getElementById('ff-'+x); if(el) el.className = 'fbtn'; });
  document.getElementById('ff-'+f).className = 'fbtn fa';
  renderFisTable();
}
function renderFisTable(){
  let list = M_FISCAL.filter(m => v2025(m,'it') != null);
  if(filtroF === 'pos') list = list.filter(m => v2025(m,'rf') != null && v2025(m,'rf') >= 0);
  if(filtroF === 'neg') list = list.filter(m => v2025(m,'rf') != null && v2025(m,'rf') < 0);

  // Si hay sort activo, usarlo. Sino: en pos/neg ordenar por RF, sino por IT desc
  if(sortState['tbody-fis']){
    list = applySort(list, 'tbody-fis', (m, col) => {
      if(col === 'nombre') return m.nombre;
      if(col === 'gk') return (m.var && m.var.gk && m.var.gk.b) ? m.var.gk.b[2] : null;
      return v2025(m, col);
    });
  } else if(filtroF === 'pos' || filtroF === 'neg'){
    list.sort((a,b) => (v2025(b,'rf')||0) - (v2025(a,'rf')||0));
  } else {
    list.sort((a,b) => (v2025(b,'it')||0) - (v2025(a,'it')||0));
  }
  // Actualizar headers
  const heads = [
    {id:'th-fis-buit', col:'bu_it', label:'Inv. sobre ingresos'},
    {id:'th-fis-bugt', col:'bu_gt', label:'Inv. sobre gastos'},
    {id:'th-fis-gpit', col:'gp_it', label:'Personal sobre ingresos'},
    {id:'th-fis-gpgt', col:'gp_gt', label:'Personal sobre gastos'},
    {id:'th-fis-it', col:'it', label:'Ingreso Total'},
    {id:'th-fis-gt', col:'gt', label:'Gasto Total'},
    {id:'th-fis-rf', col:'rf', label:'Resultado Financiero'},
  ];
  heads.forEach(h => { const th = document.getElementById(h.id); if(th) th.innerHTML = h.label + sortInd('tbody-fis', h.col); });

  function cellPct(m, key){
    const v = v2025(m, key);
    if(v == null) return '<td class="sd">s/d</td>';
    return `<td class="r">${pct2Raw(v)}</td>`;
  }
  function cellMM(m, key){
    // Tabla comparativa usa NOMINAL (m.indices[key].n)
    let v;
    if(m.indices && m.indices[key] && m.indices[key].n){
      v = m.indices[key].n[2]; // 2025
    } else {
      v = v2025(m, key);
    }
    if(v == null) return '<td class="sd">s/d</td>';
    if(key === 'rf'){
      const cls = v >= 0 ? 'ok' : 'bad';
      const sign = v < 0 ? '−' : '';
      return `<td class="${cls}">${sign}$${Math.trunc(Math.abs(v)/1000000).toLocaleString('es-AR')} M</td>`;
    }
    return `<td class="r">$${Math.trunc(v/1000000).toLocaleString('es-AR')} M</td>`;
  }

  function cellGK(m){
    // gk vive en m.var.gk.b[2]
    const v = (m.var && m.var.gk && m.var.gk.b) ? m.var.gk.b[2] : null;
    if(v == null) return '<td class="sd">s/d</td>';
    return `<td class="r">${trunc2(v*100)}%</td>`;
  }

  let rows = list.map((m,i) => `<tr${tdfRowCls(m)}>
    <td>${i+1}</td>
    <td>${m.nombre}${tdfChip(m)}${muniBadge(m)}</td>
    ${cellPct(m,'bu_it')}
    ${cellPct(m,'bu_gt')}
    ${cellPct(m,'gp_it')}
    ${cellPct(m,'gp_gt')}
    ${cellMM(m,'it')}
    ${cellMM(m,'gt')}
    ${cellMM(m,'rf')}
  </tr>`).join('');
  // Municipios sin datos fiscales al final (solo cuando no hay filtro)
  if(filtroF === 'all' && !sortState['tbody-fis']){
    const sinDatos = DATA.filter(m => m.grupo === 'sindatos');
    rows += sinDatos.map(m => `<tr style="opacity:.5">
      <td>—</td>
      <td>${m.nombre}${tdfChip(m)}${muniBadge(m)}</td>
      <td colspan="7" style="text-align:center;font-style:italic;color:var(--tx-sec)">Sin datos fiscales disponibles</td>
    </tr>`).join('');
  }
  document.getElementById('tbody-fis').innerHTML = rows;
}

// ── PBG Y COPARTICIPACIÓN ───────────────────────────────────────────────────
// Helpers que adaptan mis estructuras de datos al formato del scatter original.
// Infra en escala 0-100; PBG/CUD en % (pct_pbg y cud_2026 vienen en 0-1 → *100).
function pHasPBG(m){ return m.pbg && m.pbg.cae != null; }
function pCAE(m){ return m.pbg ? m.pbg.cae : null; }
function pPBG(m){ return m.pbg ? m.pbg.pct_pbg*100 : 0; }       // % PBG provincial
function pCUD(m){ return m.pbg ? m.pbg.cud_2026*100 : 0; }      // % CUD 2026
function pRKP(m){ return m.pbg ? m.pbg.rk_pbg : 99; }
function pRKC(m){ return m.pbg ? m.pbg.rk_cud : 99; }
function pINFRA(m){ return (m.infra && m.infra.indice!=null) ? m.infra.indice*100 : null; }  // 0-100
const M_PBG_ALL = DATA.filter(pHasPBG);

function perfilPolitico(m){
  const cae = pCAE(m), infra = pINFRA(m);
  if(infra == null) return {label:'○ Sin infra', color:'#888', bg:'#f5f5f5'};
  if(cae>1.5 && infra<55) return {label:'⚠ Injusticia fiscal', color:'#A32D2D', bg:'#FCEBEB'};
  if(cae>1.5 && infra>=55) return {label:'✦ Contribuidor servido', color:'#0F6E56', bg:'#E1F5EE'};
  if(cae<0.7 && infra>=65) return {label:'◉ Subsidiado servido', color:'#854F0B', bg:'#FAEEDA'};
  if(cae<0.7 && infra<55) return {label:'▼ Rezago estructural', color:'#7A3010', bg:'#FDE8D8'};
  if(cae>=0.7 && cae<=1.3 && infra>=65) return {label:'● Equilibrado', color:'#1e2d5a', bg:'#EAF0FB'};
  return {label:'○ Neutro', color:'#888', bg:'#f5f5f5'};
}
function getNotable(){
  const wp = M_PBG_ALL.filter(m => pPBG(m)>0);
  const bc = [...wp].sort((a,b) => pCAE(b)-pCAE(a));
  return new Set([...bc.slice(0,5).map(m=>m.nombre), ...bc.slice(-4).map(m=>m.nombre),
    bc.reduce((a,b)=>pPBG(a)>pPBG(b)?a:b).nombre, wp.reduce((a,b)=>pCUD(a)>pCUD(b)?a:b).nombre]);
}

// Viewport zoom/pan
let vp = {scale:1, tx:0, ty:0};
let scW=0, scH=0;
let zoomActive=false;  // el zoom con rueda solo actúa tras clic en el gráfico
function applyVP(px,py){ const cx=scW/2,cy=scH/2; return {x:(px-cx)*vp.scale+cx+vp.tx, y:(py-cy)*vp.scale+cy+vp.ty}; }
function updateZoomLabel(){ const el=document.getElementById('zoom-label'); if(el) el.textContent='×'+vp.scale.toFixed(1); }
function scatterZoom(factor,cx,cy){
  const c=document.getElementById('scatter-canvas'); if(!c) return;
  cx=cx??scW/2; cy=cy??scH/2;
  const newScale=Math.min(10,Math.max(0.5,vp.scale*factor));
  const ratio=newScale/vp.scale;
  const dcx=scW/2,dcy=scH/2;
  vp.tx=(vp.tx+cx-dcx)*ratio-(cx-dcx);
  vp.ty=(vp.ty+cy-dcy)*ratio-(cy-dcy);
  vp.scale=newScale; updateZoomLabel(); drawScatter();
}
function resetZoom(){ vp={scale:1,tx:0,ty:0}; updateZoomLabel(); drawScatter(); }

function drawScatter(){
  const c=document.getElementById('scatter-canvas'); if(!c) return;
  const wrap=c.parentElement;
  const W=Math.max(400,wrap.offsetWidth||500), H=360;
  c.width=W; c.height=H; c.style.display='block';
  scW=W; scH=H;
  const ctx=c.getContext('2d'); ctx.clearRect(0,0,W,H);
  const pad={t:20,r:30,b:44,l:52};
  const cw=W-pad.l-pad.r, ch=H-pad.t-pad.b;
  const pts=M_PBG_ALL.filter(m=>pPBG(m)>0);
  const maxC=Math.max(...pts.map(m=>pCUD(m)))*1.18;
  const maxP=Math.max(...pts.map(m=>pPBG(m)))*1.15;
  const bsx=v=>pad.l+(v/maxC)*cw;
  const bsy=v=>H-pad.b-(v/maxP)*ch;
  const sx=v=>applyVP(bsx(v),0).x;
  const sy=v=>applyVP(0,bsy(v)).y;
  const sxy=(cx,cy)=>applyVP(bsx(cx),bsy(cy));

  ctx.save(); ctx.beginPath(); ctx.rect(pad.l,pad.t,cw,ch+2); ctx.clip();
  ctx.strokeStyle='rgba(0,0,0,.05)'; ctx.lineWidth=.5;
  [0.5,1,1.5,2,2.5,3,3.5,4,4.5,5,6,7].forEach(v=>{
    if(v<=maxC){const x=sx(v);if(x>=pad.l&&x<=W-pad.r){ctx.beginPath();ctx.moveTo(x,pad.t);ctx.lineTo(x,H-pad.b);ctx.stroke();}}
    if(v<=maxP){const y=sy(v);if(y>=pad.t&&y<=H-pad.b){ctx.beginPath();ctx.moveTo(pad.l,y);ctx.lineTo(W-pad.r,y);ctx.stroke();}}
  });
  const d0=sxy(0,0),d1=sxy(Math.min(maxC,maxP*(maxC/maxP)),Math.min(maxP,maxC*(maxP/maxC)));
  ctx.strokeStyle='rgba(30,45,90,.22)'; ctx.lineWidth=1.5; ctx.setLineDash([8,6]);
  ctx.beginPath(); ctx.moveTo(d0.x,d0.y); ctx.lineTo(d1.x,d1.y); ctx.stroke(); ctx.setLineDash([]);

  const notable=getNotable();
  const dotData=pts.map(m=>{
    const p=sxy(pCUD(m),pPBG(m));
    const r=m.t==='grande'?7:m.t==='mediano'?5.5:4;
    const col=pCAE(m)>1?'#E24B4A':'#1D9E75';
    const tdf=esTDF(m);
    return {x:p.x,y:p.y,r,col,m,isN:notable.has(m.nombre)||tdf,tdf};
  });
  dotData.filter(d=>!d.isN).forEach(d=>{
    ctx.beginPath(); ctx.arc(d.x,d.y,d.r*vp.scale,0,2*Math.PI);
    ctx.fillStyle=d.col+'88'; ctx.fill();
    ctx.strokeStyle=d.col+'AA'; ctx.lineWidth=.7; ctx.stroke();
  });
  dotData.filter(d=>d.isN).forEach(d=>{
    if(d.tdf){
      // Anillo dorado destacado para Tres de Febrero
      ctx.beginPath(); ctx.arc(d.x,d.y,(d.r+6)*vp.scale,0,2*Math.PI);
      ctx.fillStyle='rgba(240,165,0,.20)'; ctx.fill();
      ctx.beginPath(); ctx.arc(d.x,d.y,d.r*vp.scale,0,2*Math.PI);
      ctx.fillStyle=d.col; ctx.fill();
      ctx.strokeStyle='#f0a500'; ctx.lineWidth=3; ctx.stroke();
      ctx.strokeStyle='#fff'; ctx.lineWidth=1; ctx.stroke();
    } else {
      ctx.beginPath(); ctx.arc(d.x,d.y,(d.r+3)*vp.scale,0,2*Math.PI);
      ctx.fillStyle=d.col+'22'; ctx.fill();
      ctx.beginPath(); ctx.arc(d.x,d.y,d.r*vp.scale,0,2*Math.PI);
      ctx.fillStyle=d.col; ctx.fill();
      ctx.strokeStyle='#fff'; ctx.lineWidth=1.5; ctx.stroke();
    }
  });
  ctx.restore();

  ctx.strokeStyle='rgba(0,0,0,.18)'; ctx.lineWidth=1;
  ctx.beginPath(); ctx.moveTo(pad.l,pad.t); ctx.lineTo(pad.l,H-pad.b); ctx.lineTo(W-pad.r,H-pad.b); ctx.stroke();
  ctx.font='italic 9px Inter'; ctx.fillStyle='rgba(30,45,90,.35)'; ctx.textAlign='left';
  const midD=sxy(Math.min(maxC,maxP*(maxC/maxP))*.45,Math.min(maxP,maxC*(maxP/maxC))*.45);
  if(midD.x>pad.l+10&&midD.x<W-pad.r&&midD.y>pad.t&&midD.y<H-pad.b)ctx.fillText('CAE=1',midD.x+3,midD.y-3);
  ctx.fillStyle='#999'; ctx.font='9px Inter'; ctx.textAlign='center';
  ctx.fillText('% CUD 2026 recibido →',pad.l+cw/2,H-8);
  ctx.save(); ctx.translate(14,pad.t+ch/2); ctx.rotate(-Math.PI/2); ctx.fillText('% PBG aportado →',0,0); ctx.restore();
  ctx.fillStyle='#bbb'; ctx.font='8.5px Inter'; ctx.textAlign='center';
  [1,2,3,4,5,6,7].forEach(v=>{
    const xp=sx(v); if(xp>=pad.l-1&&xp<=W-pad.r+1)ctx.fillText(v+'%',xp,H-pad.b+12);
    const yp=sy(v); if(yp>=pad.t-1&&yp<=H-pad.b+1){ctx.textAlign='right';ctx.fillText(v+'%',pad.l-4,yp+3);ctx.textAlign='center';}
  });
  // Etiquetas livianas para TODOS los puntos no-notables (texto chico al lado del dot)
  ctx.font='8px Inter'; ctx.textAlign='left';
  dotData.filter(d=>!d.isN).forEach(d=>{
    const lbl=d.m.nombre;
    const lx=d.x + d.r*vp.scale + 3;
    const ly=d.y + 3;
    // Solo dibujar si está dentro del área visible
    if(lx<pad.l-2 || lx>W-pad.r-10 || ly<pad.t || ly>H-pad.b) return;
    // Halo blanco para legibilidad
    ctx.lineWidth=2.5; ctx.strokeStyle='rgba(255,255,255,.85)';
    ctx.strokeText(lbl, lx, ly);
    ctx.fillStyle=d.col; ctx.fillText(lbl, lx, ly);
  });
  ctx.font='bold 9px Inter';
  dotData.filter(d=>d.isN).forEach(d=>{
    const lbl=d.m.nombre; const tw=ctx.measureText(lbl).width;
    const ph=13,pw=tw+8,pr=4,margin=6+d.r*vp.scale;
    const opts=[
      {lx:d.x-pw/2,ly:d.y-margin-ph,ax:d.x,ay:d.y-d.r*vp.scale-2},
      {lx:d.x+margin,ly:d.y-ph/2,ax:d.x+d.r*vp.scale+2,ay:d.y},
      {lx:d.x-pw-margin,ly:d.y-ph/2,ax:d.x-d.r*vp.scale-2,ay:d.y},
      {lx:d.x-pw/2,ly:d.y+margin,ax:d.x,ay:d.y+d.r*vp.scale+2},
    ];
    let ch2=opts[0];
    for(const o of opts){if(o.lx>=2&&o.lx+pw<=W-2&&o.ly>=2&&o.ly+ph<=H-2){ch2=o;break;}}
    const pillCol = d.tdf ? '#f0a500' : d.col;
    ctx.strokeStyle=(d.tdf?'#f0a500':d.col)+'66'; ctx.lineWidth=d.tdf?1.4:.8;
    ctx.beginPath(); ctx.moveTo(ch2.ax,ch2.ay); ctx.lineTo(ch2.lx+pw/2,ch2.ly+ph/2); ctx.stroke();
    ctx.fillStyle=pillCol; ctx.beginPath();
    if(ctx.roundRect)ctx.roundRect(ch2.lx,ch2.ly,pw,ph,pr); else ctx.rect(ch2.lx,ch2.ly,pw,ph);
    ctx.fill();
    ctx.fillStyle=d.tdf?'#1e2d5a':'#fff'; ctx.textAlign='left'; ctx.fillText(lbl,ch2.lx+4,ch2.ly+ph-3);
  });
  c._dots=dotData;
}

function setupScatterInteraction(){
  const c=document.getElementById('scatter-canvas'); const tt=document.getElementById('scatter-tt');
  const wrap=c?c.parentElement:null;
  if(!c||c._interSet) return; c._interSet=true;
  let drag=false,lastX=0,lastY=0,moved=false;
  // Zoom solo activo tras clic en el gráfico. Por defecto la rueda scrollea la página.
  function setZoomActive(on){
    zoomActive=on;
    const badge=document.getElementById('scatter-active-badge');
    const hint=document.getElementById('scatter-hint');
    if(badge) badge.style.display = on?'inline-flex':'none';
    if(hint) hint.style.display = on?'none':'inline';
    if(wrap){ wrap.style.outline = on?'2px solid var(--gold)':'none'; wrap.style.outlineOffset='1px'; }
    c.style.cursor = on?'crosshair':'pointer';
  }
  c.addEventListener('wheel',e=>{
    if(!zoomActive) return;            // sin activar: deja scrollear la página normalmente
    e.preventDefault();
    const rect=c.getBoundingClientRect();
    const mx=(e.clientX-rect.left)*(c.width/rect.width);
    const my=(e.clientY-rect.top)*(c.height/rect.height);
    scatterZoom(e.deltaY<0?1.15:1/1.15,mx,my);
  },{passive:false});
  // Clic activa el modo zoom (si no fue un arrastre)
  c.addEventListener('mousedown',e=>{drag=true;moved=false;lastX=e.clientX;lastY=e.clientY;tt.style.display='none';if(zoomActive)c.style.cursor='grabbing';});
  window.addEventListener('mouseup',()=>{if(drag){drag=false;if(zoomActive)c.style.cursor='crosshair';}});
  c.addEventListener('click',e=>{ if(!moved && !zoomActive) setZoomActive(true); });
  // Clic fuera del gráfico desactiva
  document.addEventListener('mousedown',e=>{ if(zoomActive && wrap && !wrap.contains(e.target)) setZoomActive(false); });
  document.addEventListener('keydown',e=>{ if(e.key==='Escape' && zoomActive) setZoomActive(false); });
  window.addEventListener('mousemove',e=>{
    if(drag){
      if(Math.abs(e.clientX-lastX)>3||Math.abs(e.clientY-lastY)>3) moved=true;
      if(zoomActive){const dx=e.clientX-lastX,dy=e.clientY-lastY;lastX=e.clientX;lastY=e.clientY;vp.tx+=dx;vp.ty+=dy;drawScatter();return;}
    }
    if(!c._dots){tt.style.display='none';return;}
    const rect=c.getBoundingClientRect();
    const mx=(e.clientX-rect.left)*(c.width/rect.width);
    const my=(e.clientY-rect.top)*(c.height/rect.height);
    let found=null,minD=Infinity;
    c._dots.forEach(d=>{
      const dist=Math.sqrt((mx-d.x)**2+(my-d.y)**2);
      const hitR=Math.max(d.r*vp.scale+4,8);
      if(dist<hitR&&dist<minD){minD=dist;found=d;}
    });
    if(found&&!drag){
      const m=found.m; const perf=perfilPolitico(m);
      const infraTxt = pINFRA(m)!=null ? trunc1(pINFRA(m))+'%' : 's/d';
      tt.innerHTML=`<strong>${m.nombre}</strong><br>%PBG: <strong>${trunc1(pPBG(m))}%</strong> (Rk #${pRKP(m)}) · %CUD: <strong>${trunc1(pCUD(m))}%</strong> (Rk #${pRKC(m)})<br>CAE: <strong style="color:${pCAE(m)>1?'#FCA5A5':'#6EE7B7'}">${trunc1(pCAE(m))}</strong> · Infra: ${infraTxt} · ${perf.label}`;
      const cRect=c.getBoundingClientRect(); const ex=e.clientX-cRect.left,ey=e.clientY-cRect.top;
      tt.style.left=Math.min(ex+14,cRect.width-230)+'px'; tt.style.top=Math.max(ey-85,4)+'px';
      tt.style.display='block'; if(!drag)c.style.cursor='pointer';
    } else if(!drag){tt.style.display='none';c.style.cursor=zoomActive?'crosshair':'pointer';}
  });
  c.addEventListener('mouseleave',()=>{tt.style.display='none';if(!drag)c.style.cursor=zoomActive?'crosshair':'pointer';});
  let lastDist=null;
  c.addEventListener('touchstart',e=>{if(e.touches.length===2){lastDist=Math.hypot(e.touches[0].clientX-e.touches[1].clientX,e.touches[0].clientY-e.touches[1].clientY);}},{passive:true});
  c.addEventListener('touchmove',e=>{
    if(e.touches.length===2&&lastDist){const d=Math.hypot(e.touches[0].clientX-e.touches[1].clientX,e.touches[0].clientY-e.touches[1].clientY);scatterZoom(d/lastDist);lastDist=d;}
  },{passive:true});
  c.addEventListener('touchend',()=>{lastDist=null;},{passive:true});
}

function num2cae(v){ return trunc2(v); }
function pctP(v){ return trunc1(v)+'%'; }
// Formato MM = millones de pesos. Ej: 74642600035 → "$74.643 MM"
function pesosMM(v){
  if(v==null) return '<span class="sd">s/d</span>';
  const mm = Math.round(v/1000000);
  const txt = mm.toLocaleString('es-AR');
  if(v<0) return '<span style="color:var(--bad)">−$'+(-mm).toLocaleString('es-AR')+' M</span>';
  return '$'+txt+' M';
}
function pesosMMplain(v){
  if(v==null) return null;
  const mm = Math.round(v/1000000);
  return mm.toLocaleString('es-AR');
}

function buildPBG(){
  const byCae=[...M_PBG_ALL].sort((a,b)=>pCAE(b)-pCAE(a));
  const top=byCae[0], bot=byCae[byCae.length-1];
  vp={scale:1,tx:0,ty:0}; updateZoomLabel();
  drawScatter();

  // ── Análisis CAE → Infraestructura ────────────────────────────────────────
  // Pregunta: ¿los más beneficiados (menor CAE) tienen mejor infraestructura que los más perjudicados?
  const withInfra = M_PBG_ALL.filter(m => pINFRA(m) != null);
  const byCaeAsc = [...withInfra].sort((a,b) => pCAE(a) - pCAE(b));
  const benef10 = byCaeAsc.slice(0,10);           // menor CAE = más beneficiados
  const perj10 = byCaeAsc.slice(-10).reverse();   // mayor CAE = más perjudicados
  function avgInfra(arr){ return arr.reduce((s,m)=>s+pINFRA(m),0) / arr.length; }
  const avgBenef = avgInfra(benef10);
  const avgPerj = avgInfra(perj10);
  const diff = avgBenef - avgPerj;

  document.getElementById('cae-infra-resumen').innerHTML = '';

  function caeInfraRow(m, i, isBenef){
    const cae = pCAE(m), infra = pINFRA(m);
    const caeCol = isBenef ? 'var(--ok)' : 'var(--bad)';
    const bg = isBenef ? '#E1F5EE' : '#FCEBEB';
    const tdfBg = esTDF(m) ? 'background:rgba(240,165,0,.12);box-shadow:inset 3px 0 0 var(--gold);' : '';
    return `<div style="display:flex;align-items:center;gap:8px;padding:7px 8px;border-bottom:.5px solid var(--bd-3);${tdfBg}">
      <div style="width:22px;height:22px;border-radius:50%;background:${bg};color:${caeCol};display:flex;align-items:center;justify-content:center;font-size:10px;font-weight:700;flex-shrink:0">${i+1}</div>
      <div style="flex:1;min-width:0">
        <div style="font-size:12px;font-weight:600;color:var(--tx-pri)">${m.nombre}${tdfChip(m)}</div>
        <div style="font-size:10px;color:var(--tx-sec);margin-top:1px;font-variant-numeric:tabular-nums">Agua ${pct2Raw(cov(m,'agua'))} · Cloaca ${pct2Raw(cov(m,'cloaca'))} · Gas ${pct2Raw(cov(m,'gas'))}</div>
      </div>
      <div class="cae-row-right">
        <div style="line-height:1.1">
          <span style="font-size:10px;color:#9aa1b0;font-weight:500;font-variant-numeric:tabular-nums">(PBG ${pctP(pPBG(m))} · CUD ${pctP(pCUD(m))})</span>
          <span style="font-size:11px;font-weight:700;color:${caeCol};margin-left:4px">CAE ${num2cae(cae)}</span>
        </div>
        <div style="font-size:11px;font-weight:600;color:var(--tx-pri);line-height:1.1;margin-top:2px">Infra ${pctP(infra)}</div>
      </div>
    </div>`;
  }
  document.getElementById('cae-infra-best').innerHTML = benef10.map((m,i)=>caeInfraRow(m,i,true)).join('');
  document.getElementById('cae-infra-worst').innerHTML = perj10.map((m,i)=>caeInfraRow(m,i,false)).join('');

  // Poblar selector del buscador (todos los municipios con datos de CAE e infra, alfabético)
  // Guardar globalmente el ranking completo (ascendente por CAE) para sacar la posición
  window._byCaeAscFull = byCaeAsc;
  const selBusc = document.getElementById('sel-cae-busc');
  if(selBusc){
    const alfa = [...withInfra].sort((a,b) => a.nombre.localeCompare(b.nombre, 'es'));
    selBusc.innerHTML = '<option value="">— seleccionar municipio —</option>' +
      alfa.map(m => {
        const star = esTDF(m) ? ' ★' : '';
        return `<option value="${m.nombre.replace(/"/g,'&quot;')}">${m.nombre}${star}</option>`;
      }).join('');
    selBusc.value = '';
  }
  document.getElementById('cae-infra-buscado').innerHTML = '';

  // Conclusión interpretativa
  let concl;
  if(Math.abs(diff*100) < 3){
    concl = `<strong>Resultado:</strong> la diferencia de cobertura entre los municipios con menor CAE y los de mayor CAE es chica (${diff>=0?'+':''}${pctP(diff)}). En otras palabras, <strong>recibir más coparticipación no se traduce de forma clara en mejor cobertura de servicios básicos</strong>.`;
  } else if(diff > 0){
    concl = `<strong>Resultado:</strong> los municipios con menor CAE (más beneficiados por la coparticipación) tienen en promedio <strong style="color:var(--ok)">${pctP(diff)}</strong> más de cobertura de infraestructura básica que los de mayor CAE (perjudicados). En otras palabras, <strong>los municipios que reciben más coparticipación de lo que aportan tienden a tener mejor cobertura</strong>.`;
  } else {
    concl = `<strong>Resultado:</strong> los municipios con mayor CAE (perjudicados por la coparticipación) tienen en promedio <strong style="color:var(--bad)">${pctP(-diff)}</strong> más de cobertura que los de menor CAE (beneficiados). En otras palabras, <strong>los municipios que más aportan al PBG tienden a tener mejor cobertura</strong>.`;
  }
  document.getElementById('cae-infra-conclusion').innerHTML = concl;

  // ── Cuadrantes: Beneficiados COPA y Perjudicados COPA ────────────────────
  const sc=[...M_PBG_ALL].sort((a,b)=>pCAE(b)-pCAE(a));
  document.getElementById('rank-cae-top').innerHTML=sc.slice(0,10).map((m,i)=>`<div class="rrow" style="display:flex;align-items:center;gap:7px">${rankBadge(i,'worst',20)}<div style="flex:1"><div class="rname" style="font-size:11px">${m.nombre}${tdfChip(m)}</div><div style="font-size:10px;color:var(--tx-sec)">PBG ${pctP(pPBG(m))} · CUD ${pctP(pCUD(m))}</div></div><span class="rval rvbd">${num2cae(pCAE(m))}</span></div>`).join('');
  document.getElementById('rank-cae-bot').innerHTML=sc.slice(-10).reverse().map((m,i)=>`<div class="rrow" style="display:flex;align-items:center;gap:7px">${rankBadge(i,'best',20)}<div style="flex:1"><div class="rname" style="font-size:11px">${m.nombre}${tdfChip(m)}</div><div style="font-size:10px;color:var(--tx-sec)">PBG ${pctP(pPBG(m))} · CUD ${pctP(pCUD(m))}</div></div><span class="rval rvok">${num2cae(pCAE(m))}</span></div>`).join('');
  renderTablaPBG();
  setTimeout(setupScatterInteraction,100);
}
// Ficha del municipio buscado en el análisis CAE → Infra
function renderCaeBuscado(){
  const sel = document.getElementById('sel-cae-busc');
  const cont = document.getElementById('cae-infra-buscado');
  if(!sel || !cont){ return; }
  const nombre = sel.value;
  if(!nombre || !window._byCaeAscFull){ cont.innerHTML = ''; return; }
  const ranking = window._byCaeAscFull;  // ascendente: pos 1 = más beneficiado
  const idx = ranking.findIndex(x => x.nombre === nombre);
  if(idx < 0){ cont.innerHTML = ''; return; }
  const m = ranking[idx];
  const total = ranking.length;
  const posDesdeBenef = idx + 1;
  // Beneficiado si está en la mitad inferior del ranking ascendente (menor CAE)
  const isBenef = pCAE(m) <= 1;
  const caeCol = isBenef ? 'var(--ok)' : 'var(--bad)';
  const bg = isBenef ? '#E1F5EE' : '#FCEBEB';
  const tdfBg = esTDF(m) ? 'background:rgba(240,165,0,.18);box-shadow:inset 4px 0 0 var(--gold);' : `background:${bg};`;
  const borderCol = esTDF(m) ? 'var(--gold)' : (isBenef ? '#5DCAA5' : '#F09595');
  cont.innerHTML = `<div style="display:flex;align-items:center;gap:10px;padding:10px 12px;border-radius:var(--rad-md);border:1px solid ${borderCol};${tdfBg}">
    <div style="width:28px;height:28px;border-radius:50%;background:${isBenef?'#0F6E56':'#A32D2D'};color:#fff;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:700;flex-shrink:0">#${posDesdeBenef}</div>
    <div style="flex:1;min-width:0">
      <div style="font-size:13px;font-weight:700;color:var(--tx-pri)">${m.nombre}${tdfChip(m)}</div>
      <div style="font-size:10.5px;color:var(--tx-sec);margin-top:2px">Posición ${posDesdeBenef} de ${total} ordenados por CAE (de más beneficiado a más perjudicado) · ${isBenef?'Beneficiado por la coparticipación':'Perjudicado por la coparticipación'}</div>
      <div style="font-size:10.5px;color:var(--tx-sec);margin-top:3px;font-variant-numeric:tabular-nums">Agua ${pctP(cov(m,'agua'))} · Cloaca ${pctP(cov(m,'cloaca'))} · Gas ${pctP(cov(m,'gas'))}</div>
    </div>
    <div class="cae-row-right">
      <div style="line-height:1.1">
        <span style="font-size:10px;color:#9aa1b0;font-weight:500;font-variant-numeric:tabular-nums">(PBG ${pctP(pPBG(m))} · CUD ${pctP(pCUD(m))})</span>
      </div>
      <div style="font-size:13px;font-weight:700;color:${caeCol};line-height:1.1;margin-top:2px">CAE ${num2cae(pCAE(m))}</div>
      <div style="font-size:12px;font-weight:600;color:var(--tx-pri);line-height:1.1;margin-top:3px">Infra ${pctP(pINFRA(m))}</div>
    </div>
  </div>`;
}

function renderTablaPBG(){ buildPBGTable(); }
function buildPBGTable(){
  let sorted;
  if(sortState['tbody-pbg']){
    sorted = applySort(M_PBG_ALL.filter(m=>pPBG(m)>0), 'tbody-pbg', (m, col) => {
      if(col === 'nombre') return m.nombre;
      if(col === 'pbg') return pPBG(m);
      if(col === 'cud') return pCUD(m);
      if(col === 'cae') return pCAE(m);
      if(col === 'rkp') return pRKP(m);
      if(col === 'rkc') return pRKC(m);
      if(col === 'infra') return pINFRA(m);
      return null;
    });
  } else {
    sorted = [...M_PBG_ALL].filter(m=>pPBG(m)>0).sort((a,b)=>pCAE(b)-pCAE(a));
  }
  // Indicadores en headers
  const heads = [
    {id:'th-pbg-pbg', col:'pbg', label:'%PBG 2023'},
    {id:'th-pbg-cud', col:'cud', label:'%CUD 2026'},
    {id:'th-pbg-cae', col:'cae', label:'CAE'},
    {id:'th-pbg-rkp', col:'rkp', label:'Rk PBG'},
    {id:'th-pbg-rkc', col:'rkc', label:'Rk CUD'},
    {id:'th-pbg-infra', col:'infra', label:'Infraest.'},
  ];
  heads.forEach(h => { const th = document.getElementById(h.id); if(th) th.innerHTML = h.label + sortInd('tbody-pbg', h.col); });

  document.getElementById('tbody-pbg').innerHTML = sorted.map((m, i) => {
    // Colores invertidos: CAE>1 perjudicado (rojo), CAE<1 beneficiado (verde)
    const caeColor = pCAE(m) > 1 ? 'bad' : 'ok';
    const infraTxt = pINFRA(m) != null ? pctP(pINFRA(m)) : '<span class="sd">s/d</span>';
    const infraCls = pINFRA(m) == null ? 'sd' : pINFRA(m) >= 70 ? 'ok' : pINFRA(m) >= 50 ? 'warn' : 'bad';
    return `<tr${tdfRowCls(m)}><td>${i+1}</td><td>${m.nombre}${tdfChip(m)}</td><td class="r">${trunc1(pPBG(m))}%</td><td class="r">${trunc1(pCUD(m))}%</td><td class="${caeColor}">${num2cae(pCAE(m))}</td><td class="r" style="color:var(--tx-sec)">#${pRKP(m)}</td><td class="r" style="color:var(--tx-sec)">#${pRKC(m)}</td><td class="${infraCls}">${infraTxt}</td></tr>`;
  }).join('');
}

// ── PBG 135 MUNICIPIOS ──────────────────────────────────────────────────────
// Helpers para el dataset de 135 (campos planos: cae, pct_pbg, cud_2026, icis 0-1).
const M135 = DATA135.filter(m => m.cae != null);
function q135PBG(m){ return m.pct_pbg!=null ? m.pct_pbg*100 : 0; }
function q135CUD(m){ return m.cud_2026!=null ? m.cud_2026*100 : 0; }
function q135INFRA(m){ return m.icis!=null ? m.icis*100 : null; }  // ICIS 0-100
function q135RKP(m){ return m.rk_pbg ?? '—'; }
function q135RKC(m){ return m.rk_cud ?? '—'; }
function bdg135(t){ return t==='grande'?'<span class="badge bn">G</span>':t==='mediano'?'<span class="badge bw">M</span>':t==='chico'?'<span class="badge bgray">C</span>':''; }
function perfil135(m){
  const cae=m.cae, infra=q135INFRA(m);
  if(infra==null) return {label:'○ Sin infra', color:'#888', bg:'#f5f5f5'};
  if(cae>1.5&&infra<55) return {label:'⚠ Injusticia fiscal', color:'#A32D2D', bg:'#FCEBEB'};
  if(cae>1.5&&infra>=55) return {label:'✦ Contribuidor servido', color:'#0F6E56', bg:'#E1F5EE'};
  if(cae<0.7&&infra>=65) return {label:'◉ Subsidiado servido', color:'#854F0B', bg:'#FAEEDA'};
  if(cae<0.7&&infra<55) return {label:'▼ Rezago estructural', color:'#7A3010', bg:'#FDE8D8'};
  if(cae>=0.7&&cae<=1.3&&infra>=65) return {label:'● Equilibrado', color:'#1e2d5a', bg:'#EAF0FB'};
  return {label:'○ Neutro', color:'#888', bg:'#f5f5f5'};
}

// Viewport propio para el scatter de 135
let vp135={scale:1,tx:0,ty:0}, scW135=0, scH135=0, zoomActive135=false;
function applyVP135(px,py){const cx=scW135/2,cy=scH135/2;return{x:(px-cx)*vp135.scale+cx+vp135.tx,y:(py-cy)*vp135.scale+cy+vp135.ty};}
function updateZoomLabel135(){const el=document.getElementById('zoom-label-135');if(el)el.textContent='×'+vp135.scale.toFixed(1);}
function scatterZoom135(factor,cx,cy){
  const c=document.getElementById('scatter-canvas-135');if(!c)return;
  cx=cx??scW135/2;cy=cy??scH135/2;
  const ns=Math.min(10,Math.max(0.5,vp135.scale*factor));const ratio=ns/vp135.scale;
  const dcx=scW135/2,dcy=scH135/2;
  vp135.tx=(vp135.tx+cx-dcx)*ratio-(cx-dcx);vp135.ty=(vp135.ty+cy-dcy)*ratio-(cy-dcy);
  vp135.scale=ns;updateZoomLabel135();drawScatter135();
}
function resetZoom135(){vp135={scale:1,tx:0,ty:0};updateZoomLabel135();drawScatter135();}

function drawScatter135(){
  const c=document.getElementById('scatter-canvas-135');if(!c)return;
  const wrap=c.parentElement;
  const W=Math.max(400,wrap.offsetWidth||500),H=400;
  c.width=W;c.height=H;c.style.display='block';scW135=W;scH135=H;
  const ctx=c.getContext('2d');ctx.clearRect(0,0,W,H);
  const pad={t:20,r:30,b:44,l:52};
  const cw=W-pad.l-pad.r,ch=H-pad.t-pad.b;
  const pts=M135.filter(m=>q135PBG(m)>0);
  const maxC=Math.max(...pts.map(m=>q135CUD(m)))*1.18;
  const maxP=Math.max(...pts.map(m=>q135PBG(m)))*1.15;
  const bsx=v=>pad.l+(v/maxC)*cw, bsy=v=>H-pad.b-(v/maxP)*ch;
  const sx=v=>applyVP135(bsx(v),0).x, sy=v=>applyVP135(0,bsy(v)).y;
  const sxy=(cx,cy)=>applyVP135(bsx(cx),bsy(cy));

  ctx.save();ctx.beginPath();ctx.rect(pad.l,pad.t,cw,ch+2);ctx.clip();
  ctx.strokeStyle='rgba(0,0,0,.05)';ctx.lineWidth=.5;
  [0.5,1,1.5,2,2.5,3,3.5,4,4.5,5,6,7,8].forEach(v=>{
    if(v<=maxC){const x=sx(v);if(x>=pad.l&&x<=W-pad.r){ctx.beginPath();ctx.moveTo(x,pad.t);ctx.lineTo(x,H-pad.b);ctx.stroke();}}
    if(v<=maxP){const y=sy(v);if(y>=pad.t&&y<=H-pad.b){ctx.beginPath();ctx.moveTo(pad.l,y);ctx.lineTo(W-pad.r,y);ctx.stroke();}}
  });
  const d0=sxy(0,0),d1=sxy(Math.min(maxC,maxP*(maxC/maxP)),Math.min(maxP,maxC*(maxP/maxC)));
  ctx.strokeStyle='rgba(30,45,90,.22)';ctx.lineWidth=1.5;ctx.setLineDash([8,6]);
  ctx.beginPath();ctx.moveTo(d0.x,d0.y);ctx.lineTo(d1.x,d1.y);ctx.stroke();ctx.setLineDash([]);

  const dotData=pts.map(m=>{
    const p=sxy(q135CUD(m),q135PBG(m));
    const r=m.t==='grande'?7:m.t==='mediano'?5.5:4;
    const col=m.cae>1?'#E24B4A':'#1D9E75';
    const tdf=esTDF(m);
    return {x:p.x,y:p.y,r,col,m,tdf};
  });
  dotData.forEach(d=>{
    if(d.tdf){
      ctx.beginPath();ctx.arc(d.x,d.y,(d.r+6)*vp135.scale,0,2*Math.PI);ctx.fillStyle='rgba(240,165,0,.20)';ctx.fill();
      ctx.beginPath();ctx.arc(d.x,d.y,d.r*vp135.scale,0,2*Math.PI);ctx.fillStyle=d.col;ctx.fill();
      ctx.strokeStyle='#f0a500';ctx.lineWidth=3;ctx.stroke();ctx.strokeStyle='#fff';ctx.lineWidth=1;ctx.stroke();
    } else {
      ctx.beginPath();ctx.arc(d.x,d.y,d.r*vp135.scale,0,2*Math.PI);ctx.fillStyle=d.col+'AA';ctx.fill();
      ctx.strokeStyle='#fff';ctx.lineWidth=.8;ctx.stroke();
    }
  });
  ctx.restore();

  ctx.strokeStyle='rgba(0,0,0,.18)';ctx.lineWidth=1;
  ctx.beginPath();ctx.moveTo(pad.l,pad.t);ctx.lineTo(pad.l,H-pad.b);ctx.lineTo(W-pad.r,H-pad.b);ctx.stroke();
  ctx.font='italic 9px Inter';ctx.fillStyle='rgba(30,45,90,.35)';ctx.textAlign='left';
  const midD=sxy(Math.min(maxC,maxP*(maxC/maxP))*.45,Math.min(maxP,maxC*(maxP/maxC))*.45);
  if(midD.x>pad.l+10&&midD.x<W-pad.r&&midD.y>pad.t&&midD.y<H-pad.b)ctx.fillText('CAE=1',midD.x+3,midD.y-3);
  ctx.fillStyle='#999';ctx.font='9px Inter';ctx.textAlign='center';
  ctx.fillText('% CUD recibido →',pad.l+cw/2,H-8);
  ctx.save();ctx.translate(14,pad.t+ch/2);ctx.rotate(-Math.PI/2);ctx.fillText('% PBG aportado →',0,0);ctx.restore();
  ctx.fillStyle='#bbb';ctx.font='8.5px Inter';ctx.textAlign='center';
  [1,2,3,4,5,6,7,8].forEach(v=>{
    const xp=sx(v);if(xp>=pad.l-1&&xp<=W-pad.r+1)ctx.fillText(v+'%',xp,H-pad.b+12);
    const yp=sy(v);if(yp>=pad.t-1&&yp<=H-pad.b+1){ctx.textAlign='right';ctx.fillText(v+'%',pad.l-4,yp+3);ctx.textAlign='center';}
  });
  // Etiquetas de texto para TODOS los puntos
  ctx.font='7.5px Inter';ctx.textAlign='left';
  dotData.forEach(d=>{
    if(d.tdf) return;  // TDF se dibuja con pill abajo
    const lbl=d.m.nombre;
    const lx=d.x+d.r*vp135.scale+2, ly=d.y+3;
    if(lx<pad.l-2||lx>W-pad.r-6||ly<pad.t||ly>H-pad.b) return;
    ctx.lineWidth=2.5;ctx.strokeStyle='rgba(255,255,255,.85)';ctx.strokeText(lbl,lx,ly);
    ctx.fillStyle=d.col;ctx.fillText(lbl,lx,ly);
  });
  // Pill dorada para TDF
  ctx.font='bold 9px Inter';
  dotData.filter(d=>d.tdf).forEach(d=>{
    const lbl=d.m.nombre;const tw=ctx.measureText(lbl).width;
    const ph=13,pw=tw+8,pr=4,margin=6+d.r*vp135.scale;
    let lx=d.x-pw/2, ly=d.y-margin-ph;
    if(ly<2) ly=d.y+margin;
    lx=Math.max(2,Math.min(lx,W-pw-2));
    ctx.fillStyle='#f0a500';ctx.beginPath();
    if(ctx.roundRect)ctx.roundRect(lx,ly,pw,ph,pr);else ctx.rect(lx,ly,pw,ph);
    ctx.fill();
    ctx.fillStyle='#1e2d5a';ctx.textAlign='left';ctx.fillText(lbl,lx+4,ly+ph-3);
  });
  c._dots=dotData;
}

function setupScatter135(){
  const c=document.getElementById('scatter-canvas-135');const tt=document.getElementById('scatter-tt-135');
  const wrap=c?c.parentElement:null;
  if(!c||c._interSet)return;c._interSet=true;
  let drag=false,lastX=0,lastY=0,moved=false;
  function setZA(on){
    zoomActive135=on;
    const b=document.getElementById('scatter-active-badge-135'),hn=document.getElementById('scatter-hint-135');
    if(b)b.style.display=on?'inline-flex':'none';
    if(hn)hn.style.display=on?'none':'inline';
    if(wrap){wrap.style.outline=on?'2px solid var(--gold)':'none';wrap.style.outlineOffset='1px';}
    c.style.cursor=on?'crosshair':'pointer';
  }
  c.addEventListener('wheel',e=>{
    if(!zoomActive135)return;
    e.preventDefault();
    const rect=c.getBoundingClientRect();
    const mx=(e.clientX-rect.left)*(c.width/rect.width),my=(e.clientY-rect.top)*(c.height/rect.height);
    scatterZoom135(e.deltaY<0?1.15:1/1.15,mx,my);
  },{passive:false});
  c.addEventListener('mousedown',e=>{drag=true;moved=false;lastX=e.clientX;lastY=e.clientY;tt.style.display='none';if(zoomActive135)c.style.cursor='grabbing';});
  window.addEventListener('mouseup',()=>{if(drag){drag=false;if(zoomActive135)c.style.cursor='crosshair';}});
  c.addEventListener('click',()=>{if(!moved&&!zoomActive135)setZA(true);});
  document.addEventListener('mousedown',e=>{if(zoomActive135&&wrap&&!wrap.contains(e.target))setZA(false);});
  document.addEventListener('keydown',e=>{if(e.key==='Escape'&&zoomActive135)setZA(false);});
  window.addEventListener('mousemove',e=>{
    if(drag){
      if(Math.abs(e.clientX-lastX)>3||Math.abs(e.clientY-lastY)>3)moved=true;
      if(zoomActive135){const dx=e.clientX-lastX,dy=e.clientY-lastY;lastX=e.clientX;lastY=e.clientY;vp135.tx+=dx;vp135.ty+=dy;drawScatter135();return;}
    }
    if(!c._dots){tt.style.display='none';return;}
    const rect=c.getBoundingClientRect();
    const mx=(e.clientX-rect.left)*(c.width/rect.width),my=(e.clientY-rect.top)*(c.height/rect.height);
    let found=null,minD=Infinity;
    c._dots.forEach(d=>{const dist=Math.sqrt((mx-d.x)**2+(my-d.y)**2);const hitR=Math.max(d.r*vp135.scale+4,8);if(dist<hitR&&dist<minD){minD=dist;found=d;}});
    if(found&&!drag){
      const m=found.m;const perf=perfil135(m);
      const infraTxt=q135INFRA(m)!=null?pctP(q135INFRA(m)):'s/d';
      tt.innerHTML=`<strong>${m.nombre}</strong><br>%PBG: <strong>${trunc1(q135PBG(m))}%</strong> (Rk #${q135RKP(m)}) · %CUD: <strong>${trunc1(q135CUD(m))}%</strong> (Rk #${q135RKC(m)})<br>CAE: <strong style="color:${m.cae>1?'#FCA5A5':'#6EE7B7'}">${num2cae(m.cae)}</strong> · Infra: ${infraTxt} · ${perf.label}`;
      const cRect=c.getBoundingClientRect();const ex=e.clientX-cRect.left,ey=e.clientY-cRect.top;
      tt.style.left=Math.min(ex+14,cRect.width-230)+'px';tt.style.top=Math.max(ey-85,4)+'px';
      tt.style.display='block';if(!drag)c.style.cursor='pointer';
    } else if(!drag){tt.style.display='none';c.style.cursor=zoomActive135?'crosshair':'pointer';}
  });
  c.addEventListener('mouseleave',()=>{tt.style.display='none';if(!drag)c.style.cursor=zoomActive135?'crosshair':'pointer';});
  let lastDist=null;
  c.addEventListener('touchstart',e=>{if(e.touches.length===2){lastDist=Math.hypot(e.touches[0].clientX-e.touches[1].clientX,e.touches[0].clientY-e.touches[1].clientY);}},{passive:true});
  c.addEventListener('touchmove',e=>{if(e.touches.length===2&&lastDist){const d=Math.hypot(e.touches[0].clientX-e.touches[1].clientX,e.touches[0].clientY-e.touches[1].clientY);scatterZoom135(d/lastDist);lastDist=d;}},{passive:true});
  c.addEventListener('touchend',()=>{lastDist=null;},{passive:true});
}

function buildP135(){
  const byCae=[...M135].sort((a,b)=>b.cae-a.cae);
  const top=byCae[0], bot=byCae[byCae.length-1];
  vp135={scale:1,tx:0,ty:0};updateZoomLabel135();
  drawScatter135();

  // ── Análisis CAE → Infraestructura ────────────────────────────────────────
  const withInfra135 = M135.filter(m => q135INFRA(m) != null);
  const byCaeAsc135 = [...withInfra135].sort((a,b) => a.cae - b.cae);
  const benef10 = byCaeAsc135.slice(0,10);
  const perj10 = byCaeAsc135.slice(-10).reverse();
  function avgInfra135(arr){ return arr.reduce((s,m)=>s+q135INFRA(m),0) / arr.length; }
  const avgBenef = avgInfra135(benef10);
  const avgPerj = avgInfra135(perj10);
  const diff = avgBenef - avgPerj;

  document.getElementById('cae-infra-resumen-135').innerHTML = '';

  function caeInfraRow135(m, i, isBenef){
    const cae = m.cae, infra = q135INFRA(m);
    const caeCol = isBenef ? 'var(--ok)' : 'var(--bad)';
    const bg = isBenef ? '#E1F5EE' : '#FCEBEB';
    const tdfBg = esTDF(m) ? 'background:rgba(240,165,0,.12);box-shadow:inset 3px 0 0 var(--gold);' : '';
    return `<div style="display:flex;align-items:center;gap:8px;padding:7px 8px;border-bottom:.5px solid var(--bd-3);${tdfBg}">
      <div style="width:22px;height:22px;border-radius:50%;background:${bg};color:${caeCol};display:flex;align-items:center;justify-content:center;font-size:10px;font-weight:700;flex-shrink:0">${i+1}</div>
      <div style="flex:1;min-width:0">
        <div style="font-size:12px;font-weight:600;color:var(--tx-pri)">${m.nombre}${tdfChip(m)}</div>
        <div style="font-size:10px;color:var(--tx-sec);margin-top:1px;font-variant-numeric:tabular-nums">${m.region||''}</div>
      </div>
      <div class="cae-row-right">
        <div style="line-height:1.1">
          <span style="font-size:10px;color:#9aa1b0;font-weight:500;font-variant-numeric:tabular-nums">(PBG ${trunc1(q135PBG(m))}% · CUD ${trunc1(q135CUD(m))}%)</span>
          <span style="font-size:11px;font-weight:700;color:${caeCol};margin-left:4px">CAE ${num2cae(cae)}</span>
        </div>
        <div style="font-size:11px;font-weight:600;color:var(--tx-pri);line-height:1.1;margin-top:2px">ICIS ${pctP(infra)}</div>
      </div>
    </div>`;
  }
  document.getElementById('cae-infra-best-135').innerHTML = benef10.map((m,i)=>caeInfraRow135(m,i,true)).join('');
  document.getElementById('cae-infra-worst-135').innerHTML = perj10.map((m,i)=>caeInfraRow135(m,i,false)).join('');

  // Buscador 135
  window._byCaeAscFull135 = byCaeAsc135;
  const selBusc135 = document.getElementById('sel-cae-busc-135');
  if(selBusc135){
    const alfa = [...withInfra135].sort((a,b) => a.nombre.localeCompare(b.nombre, 'es'));
    selBusc135.innerHTML = '<option value="">— seleccionar municipio —</option>' +
      alfa.map(m => {
        const star = esTDF(m) ? ' ★' : '';
        return `<option value="${m.nombre.replace(/"/g,'&quot;')}">${m.nombre}${star}</option>`;
      }).join('');
    selBusc135.value = '';
  }
  document.getElementById('cae-infra-buscado-135').innerHTML = '';

  // Conclusión interpretativa
  let concl;
  if(Math.abs(diff) < 3){
    concl = `<strong>Resultado:</strong> la diferencia de cobertura entre los municipios con menor CAE y los de mayor CAE es chica (${diff>=0?'+':''}${pctP(diff)}). En otras palabras, <strong>recibir más coparticipación no se traduce de forma clara en mejor cobertura de servicios básicos</strong> en el universo de 135 municipios.`;
  } else if(diff > 0){
    concl = `<strong>Resultado:</strong> los municipios con menor CAE (más beneficiados) tienen en promedio <strong style="color:var(--ok)">${pctP(diff)}</strong> más de cobertura ICIS que los de mayor CAE (perjudicados). En otras palabras, <strong>los municipios que reciben más coparticipación de lo que aportan tienden a tener mejor cobertura</strong>.`;
  } else {
    concl = `<strong>Resultado:</strong> los municipios con mayor CAE (perjudicados) tienen en promedio <strong style="color:var(--bad)">${pctP(-diff)}</strong> más de cobertura ICIS que los de menor CAE (beneficiados). En otras palabras, <strong>los municipios que más aportan al PBG tienden a tener mejor cobertura</strong>.`;
  }
  document.getElementById('cae-infra-conclusion-135').innerHTML = concl;

  const sc=[...M135].sort((a,b)=>b.cae-a.cae);
  document.getElementById('rank-cae-top-135').innerHTML=sc.slice(0,10).map((m,i)=>`<div class="rrow" style="display:flex;align-items:center;gap:7px">${rankBadge(i,'worst',20)}<div style="flex:1"><div class="rname" style="font-size:11px">${m.nombre}${tdfChip(m)}</div><div style="font-size:10px;color:var(--tx-sec)">PBG ${pctP(q135PBG(m))} · CUD ${pctP(q135CUD(m))}</div></div><span class="rval rvbd">${num2cae(m.cae)}</span></div>`).join('');
  document.getElementById('rank-cae-bot-135').innerHTML=sc.slice(-10).reverse().map((m,i)=>`<div class="rrow" style="display:flex;align-items:center;gap:7px">${rankBadge(i,'best',20)}<div style="flex:1"><div class="rname" style="font-size:11px">${m.nombre}${tdfChip(m)}</div><div style="font-size:10px;color:var(--tx-sec)">PBG ${pctP(q135PBG(m))} · CUD ${pctP(q135CUD(m))}</div></div><span class="rval rvok">${num2cae(m.cae)}</span></div>`).join('');
  renderTablaP135();
  setTimeout(setupScatter135,100);
}

