// ── PANEL POR MUNICIPIO ─────────────────────────────────────────────────────
// Colores por sección electoral
const SECCION_COLORS = {
  1: '#1e2d5a', 2: '#f0a500', 3: '#1F7A3F', 4: '#C53030',
  5: '#4A6FAA', 6: '#E89547', 7: '#6D5BBA', 8: '#D946EF'
};
function seccionColor(sec){ return SECCION_COLORS[sec] || 'var(--bd-2)'; }

let pmunFilter = 'all';  // 'all' o 's1'..'s8'

let pmunSelected = ['Tres de Febrero'];   // Array de nombres de municipios elegidos (TDF incluido por default pero removible)

function setPmunFilter(f){
  pmunFilter = f;
  ['all','s1','s2','s3','s4','s5','s6','s7','s8'].forEach(x => {
    const el = document.getElementById('pmun-f-'+x);
    if(el) el.className = 'fbtn';
  });
  const elActive = document.getElementById('pmun-f-'+f);
  if(elActive) elActive.className = 'fbtn fa';
  // Si se selecciona una sección específica, autoseleccionar TODOS los munis de esa sección
  if(f.startsWith('s')){
    const secNum = parseInt(f.slice(1));
    pmunSelected = DATA
      .filter(m => m.seccion === secNum && m.grupo !== 'sindatos')
      .map(m => m.nombre);
  }
  populatePmunSel();
  renderPmunFichas();
}

function populatePmunSel(){
  const sel = document.getElementById('sel-pmun-add');
  if(!sel) return;
  // Excluir solo los ya seleccionados (TDF puede agregarse libremente)
  let list = DATA.filter(m => !pmunSelected.includes(m.nombre));
  if(pmunFilter.startsWith('s')){
    const secNum = parseInt(pmunFilter.slice(1));
    list = list.filter(m => m.seccion === secNum);
  }
  list.sort((a,b) => a.nombre.localeCompare(b.nombre, 'es'));
  sel.innerHTML = '<option value="">— seleccionar municipio —</option>' +
    list.map(m => {
      const sec = m.seccion ? ` (S${m.seccion}°)` : '';
      const sd = m.grupo === 'sindatos' ? ' · s/d' : '';
      return `<option value="${m.nombre.replace(/"/g,'&quot;')}">${m.nombre}${sec}${sd}</option>`;
    }).join('');
  sel.value = '';
}

function addPmun(){
  const sel = document.getElementById('sel-pmun-add');
  const n = sel.value;
  if(!n) return;
  if(!pmunSelected.includes(n)) pmunSelected.push(n);
  sel.value = '';
  populatePmunSel();
  renderPmunFichas();
}

function removePmun(name){
  pmunSelected = pmunSelected.filter(x => x !== name);
  populatePmunSel();
  renderPmunFichas();
}

function clearPmun(){
  pmunSelected = [];
  populatePmunSel();
  renderPmunFichas();
}

// ── Drag and drop: reordenar fichas ────────────────────────────────────────
let pmunDragSrc = null;
function pmunDragStart(e){
  pmunDragSrc = e.currentTarget.getAttribute('data-muni');
  e.currentTarget.classList.add('dragging');
  e.dataTransfer.effectAllowed = 'move';
  // Firefox: necesita setData para que arranque el drag
  try { e.dataTransfer.setData('text/plain', pmunDragSrc); } catch(_) {}
}
function pmunDragEnd(e){
  e.currentTarget.classList.remove('dragging');
  // Limpiar todos los drag-over que hubieran quedado
  document.querySelectorAll('.pmun-ficha.drag-over').forEach(el => el.classList.remove('drag-over'));
  pmunDragSrc = null;
}
function pmunDragOver(e){
  if(pmunDragSrc == null) return;
  e.preventDefault();
  e.dataTransfer.dropEffect = 'move';
  // Marcar visualmente solo el target actual (no el src)
  const target = e.currentTarget;
  const targetMuni = target.getAttribute('data-muni');
  if(targetMuni !== pmunDragSrc) target.classList.add('drag-over');
}
function pmunDragLeave(e){
  e.currentTarget.classList.remove('drag-over');
}
function pmunDrop(e){
  e.preventDefault();
  e.currentTarget.classList.remove('drag-over');
  const targetMuni = e.currentTarget.getAttribute('data-muni');
  if(!pmunDragSrc || pmunDragSrc === targetMuni) return;
  // Reordenar el array pmunSelected: mover src antes de target
  const srcIdx = pmunSelected.indexOf(pmunDragSrc);
  const tgtIdx = pmunSelected.indexOf(targetMuni);
  if(srcIdx < 0 || tgtIdx < 0) return;
  pmunSelected.splice(srcIdx, 1);
  // Si src estaba antes del target, el target ahora está en tgtIdx-1
  const newTgtIdx = srcIdx < tgtIdx ? tgtIdx - 1 : tgtIdx;
  // Decidir si insertar antes o después según posición horizontal del mouse
  const rect = e.currentTarget.getBoundingClientRect();
  const insertAfter = (e.clientX - rect.left) > rect.width / 2;
  const insertAt = insertAfter ? newTgtIdx + 1 : newTgtIdx;
  pmunSelected.splice(insertAt, 0, pmunDragSrc);
  renderPmunFichas();
}

function buildPmun(){
  populatePmunSel();
  renderPmunFichas();
}

// Helpers para datos de cada municipio
function pmunGetInfra(m){
  if(!m.infra) return null;
  return {
    agua: m.infra.agua,
    cloaca: m.infra.cloaca,
    gas: m.infra.gas,
    indice: m.infra.indice != null ? m.infra.indice * 100 : null
  };
}
function pmunGetCAE(m){
  if(!m.pbg || m.pbg.cae == null) return null;
  return {
    pbg: m.pbg.pct_pbg != null ? m.pbg.pct_pbg * 100 : null,
    cud: m.pbg.cud_2026 != null ? m.pbg.cud_2026 * 100 : null,
    cae: m.pbg.cae
  };
}
function pmunGetFiscal(m){
  if(!m.indices) return null;
  function last(arr){ return arr && arr.length ? arr[arr.length-1] : null; }
  return {
    bu_it: last(m.indices.bu_it && m.indices.bu_it.r) != null ? last(m.indices.bu_it.r)*100 : null,
    bu_gt: last(m.indices.bu_gt && m.indices.bu_gt.r) != null ? last(m.indices.bu_gt.r)*100 : null,
    gp_it: last(m.indices.gp_it && m.indices.gp_it.r) != null ? last(m.indices.gp_it.r)*100 : null,
    gp_gt: last(m.indices.gp_gt && m.indices.gp_gt.r) != null ? last(m.indices.gp_gt.r)*100 : null,
    it: last(m.indices.it && m.indices.it.r),
    gt: last(m.indices.gt && m.indices.gt.r),
    rf: last(m.indices.rf && m.indices.rf.r)
  };
}
function pmunGetAlic(m){
  if(!m.alic_new) return null;
  return {
    banca: m.alic_new.banca,
    banca_base: m.alic_new.banca_base,
    hipermercado: m.alic_new.hipermercado,
    industria: m.alic_new.industria,
    comercio: m.alic_new.comercio,
    mayorista: m.alic_new.mayorista,
  };
}

// Calcular máximos para escalar barras (siempre considerando TDF + seleccionados)
function pmunCalcMax(munis){
  const max = { bu_it:1, bu_gt:1, gp_it:1, gp_gt:1, it:1, gt:1, rf_abs:1 };
  munis.forEach(m => {
    const f = pmunGetFiscal(m);
    if(!f) return;
    ['bu_it','bu_gt','gp_it','gp_gt'].forEach(k => { if(f[k] != null && f[k] > max[k]) max[k] = f[k]; });
    if(f.it != null && Math.abs(f.it) > max.it) max.it = Math.abs(f.it);
    if(f.gt != null && Math.abs(f.gt) > max.gt) max.gt = Math.abs(f.gt);
    if(f.rf != null && Math.abs(f.rf) > max.rf_abs) max.rf_abs = Math.abs(f.rf);
  });
  return max;
}

function renderPmunFichas(){
  const cont = document.getElementById('pmun-fichas');
  if(!cont) return;
  const munis = pmunSelected.map(n => DATA.find(m => m.nombre === n)).filter(Boolean);
  if(munis.length === 0){
    cont.innerHTML = '<div style="padding:24px;color:var(--tx-sec);font-style:italic;font-size:12px;text-align:center;grid-column:1/-1">No hay municipios seleccionados. Agregá uno desde el selector arriba.</div>';
    return;
  }
  const maxs = pmunCalcMax(munis);
  cont.innerHTML = munis.map(m => renderPmunFicha(m, maxs)).join('');
}

function renderPmunFicha(m, maxs){
  const isTDF = m.nombre === 'Tres de Febrero';
  const infra = pmunGetInfra(m);
  const cae = pmunGetCAE(m);
  const fis = pmunGetFiscal(m);
  const ali = pmunGetAlic(m);
  const secLbl = m.seccion ? `S${m.seccion}°` : '';

  function fmtPct(v){ return v == null ? '<span style="color:var(--tx-sec);font-style:italic">s/d</span>' : trunc1(v)+'%'; }
  function fmtMMShort(v){
    if(v == null) return '<span style="color:var(--tx-sec);font-style:italic">s/d</span>';
    const sign = v < 0 ? '−' : '';
    const mm = Math.round(Math.abs(v)/1000000);
    return sign + '$' + mm.toLocaleString('es-AR') + ' M';
  }
  function caeColor(c){ if(c == null) return 'var(--tx-pri)'; return c > 1 ? 'var(--bad)' : 'var(--ok)'; }
  function rfColor(v){ if(v == null) return 'var(--tx-pri)'; return v >= 0 ? 'var(--ok)' : 'var(--bad)'; }
  function infraBar(v){
    if(v == null) return '<div class="pmun-bar"></div>';
    const w = Math.min(100, Math.max(0, v));
    const col = v >= 70 ? '#1D9E75' : v >= 40 ? '#FAC775' : '#E24B4A';
    return `<div class="pmun-bar"><div class="pmun-bar-fill" style="width:${w}%;background:${col}"></div></div>`;
  }

  const closeBtn = isTDF ? '<span style="font-size:9px;font-weight:600;opacity:.7;padding:0 4px">FIJO</span>' :
    `<button class="pmun-ficha-close" onclick="removePmun('${m.nombre.replace(/'/g,"\\'")}')" title="Quitar">×</button>`;

  // Drag handle (solo no-TDF)
  const dragHandle = isTDF ? '' : '<span class="pmun-drag-handle" title="Arrastrar para reordenar">⋮⋮</span>';

  // Atributos de drag (solo no-TDF)
  const dragAttrs = isTDF ? '' :
    ` draggable="true" data-muni="${m.nombre.replace(/"/g,'&quot;')}" ondragstart="pmunDragStart(event)" ondragend="pmunDragEnd(event)" ondragover="pmunDragOver(event)" ondragleave="pmunDragLeave(event)" ondrop="pmunDrop(event)"`;

  // Color de la sección electoral
  const secCol = m.seccion ? seccionColor(m.seccion) : null;
  const fichaStyle = (!isTDF && secCol) ? ` style="border-left:4px solid ${secCol}"` : '';
  const headerStyle = (!isTDF && secCol) ? ` style="background:${secCol}"` : '';

  return `<div class="pmun-ficha${isTDF ? ' tdf' : ''}"${dragAttrs}${fichaStyle}>
    <div class="pmun-ficha-header"${headerStyle}>
      <div style="flex:1;min-width:0;display:flex;align-items:center">
        ${dragHandle}
        <div style="flex:1;min-width:0">
          <div class="pmun-ficha-name" title="${m.nombre}">${m.nombre}</div>
          ${secLbl ? `<div class="pmun-ficha-sec">${secLbl} sección</div>` : ''}
        </div>
      </div>
      ${closeBtn}
    </div>

    <div class="pmun-grid">
      <!-- Infraestructura -->
      <div class="pmun-section">
        <div class="pmun-section-title">🚿 Infra</div>
        ${infra ? `
          <div class="pmun-row"><span class="lbl">Agua</span><span class="val">${fmtPct(infra.agua)}</span></div>
          ${infraBar(infra.agua)}
          <div class="pmun-row"><span class="lbl">Cloaca</span><span class="val">${fmtPct(infra.cloaca)}</span></div>
          ${infraBar(infra.cloaca)}
          <div class="pmun-row"><span class="lbl">Gas</span><span class="val">${fmtPct(infra.gas)}</span></div>
          ${infraBar(infra.gas)}
          <div class="pmun-row" style="border-top:.5px dotted var(--bd-3);padding-top:3px;margin-top:2px"><span class="lbl"><strong>Índice</strong></span><span class="val" style="color:${infra.indice >= 70 ? 'var(--ok)' : infra.indice >= 40 ? 'var(--warn)' : 'var(--bad)'}"><strong>${fmtPct(infra.indice)}</strong></span></div>
        ` : '<div style="color:var(--tx-sec);font-style:italic;font-size:10px;text-align:center;padding:8px 0">Sin datos</div>'}
      </div>

      <!-- CAE -->
      <div class="pmun-section">
        <div class="pmun-section-title">📊 CAE</div>
        ${cae ? `
          <div class="pmun-row"><span class="lbl">% PBG</span><span class="val">${fmtPct(cae.pbg)}</span></div>
          <div class="pmun-row"><span class="lbl">% CUD</span><span class="val">${fmtPct(cae.cud)}</span></div>
          <div class="pmun-row" style="border-top:.5px dotted var(--bd-3);padding-top:3px;margin-top:2px"><span class="lbl"><strong>CAE</strong></span><span class="val" style="color:${caeColor(cae.cae)};font-weight:700">${num2cae(cae.cae)}</span></div>
        ` : '<div style="color:var(--tx-sec);font-style:italic;font-size:10px;text-align:center;padding:8px 0">Sin datos</div>'}
        ${m.indice_fiscal ? (() => {
          const cq = m.indice_fiscal.cuartil;
          const col = cuartilColor(cq);
          const labels = {Q1:'menor carga', Q2:'medio-bajo', Q3:'medio-alto', Q4:'mayor carga'};
          const txt = labels[cq] || cq;
          // Color de fondo claro y borde con el color del cuartil
          const colMap = {Q1:'#E1F5EE', Q2:'#FDF6E0', Q3:'#FCE9DD', Q4:'#FCEBEB'};
          const bg = colMap[cq] || '#f4f4f5';
          const border = col;
          return `<div style="text-align:center;margin-top:8px;padding:6px 4px;background:${bg};border-radius:4px;border:.5px solid ${border}">
            <div style="font-size:9px;color:${col};font-weight:600;text-transform:uppercase;letter-spacing:.3px">Presión Fiscal</div>
            <div style="font-size:18px;font-weight:700;color:${col};line-height:1;margin:2px 0">${trunc2(m.indice_fiscal.total)}%</div>
            <div style="font-size:9px;color:${col};font-weight:500">${cq} (${txt})</div>
          </div>`;
        })() : ''}
      </div>

      <!-- Fiscal -->
      <div class="pmun-section">
        <div class="pmun-section-title">💰 Fiscal 2025 (real)</div>${m.nota_fiscal ? `<div style="font-size:8.5px;color:#854F0B;background:#FFF7E6;border:.5px solid #F2C97A;padding:3px 5px;border-radius:3px;margin-bottom:4px;line-height:1.25"><strong>⚠ Cobertura parcial:</strong> ${m.nota_fiscal}</div>` : ''}
        ${fis ? `
          <div class="pmun-row"><span class="lbl">Inv./Ing.</span><span class="val">${fmtPct(fis.bu_it)}</span></div>
          <div class="pmun-row"><span class="lbl">Pers./Ing.</span><span class="val">${fmtPct(fis.gp_it)}</span></div>
          <div class="pmun-row" style="margin-top:3px"><span class="lbl">IT</span><span class="val" style="font-size:9.5px">${fmtMMShort(fis.it)}</span></div>
          <div class="pmun-row"><span class="lbl">GT</span><span class="val" style="font-size:9.5px">${fmtMMShort(fis.gt)}</span></div>
          <div class="pmun-row" style="border-top:.5px dotted var(--bd-3);padding-top:3px;margin-top:2px"><span class="lbl"><strong>RF</strong></span><span class="val" style="color:${rfColor(fis.rf)};font-size:9.5px"><strong>${fmtMMShort(fis.rf)}</strong></span></div>
        ` : '<div style="color:var(--tx-sec);font-style:italic;font-size:10px;text-align:center;padding:8px 0">Sin datos</div>'}
      </div>

      <!-- Alícuotas -->
      <div class="pmun-section">
        <div class="pmun-section-title">📋 Alícuotas</div>
        ${ali ? `
          <div class="pmun-row"><span class="lbl">Banca Min.</span><span class="val">${ali.banca != null ? trunc2(ali.banca)+'%' + (ali.banca_base ? ` <span style="font-size:8.5px;color:var(--tx-sec);font-weight:500">(${ali.banca_base})</span>` : '') : '<span style="color:var(--tx-sec);font-style:italic">s/d</span>'}</span></div>
          <div class="pmun-row"><span class="lbl">Hipermercado</span><span class="val">${ali.hipermercado != null ? trunc2(ali.hipermercado)+'%' : '<span style="color:var(--tx-sec);font-style:italic">s/d</span>'}</span></div>
          <div class="pmun-row"><span class="lbl">Industria</span><span class="val">${ali.industria != null ? trunc2(ali.industria)+'%' : '<span style="color:var(--tx-sec);font-style:italic">s/d</span>'}</span></div>
          <div class="pmun-row"><span class="lbl">Comercio</span><span class="val">${ali.comercio != null ? trunc2(ali.comercio)+'%' : '<span style="color:var(--tx-sec);font-style:italic">s/d</span>'}</span></div>
          <div class="pmun-row"><span class="lbl">C. Mayorista</span><span class="val">${ali.mayorista != null ? trunc2(ali.mayorista)+'%' : '<span style="color:var(--tx-sec);font-style:italic">s/d</span>'}</span></div>
        ` : '<div style="color:var(--tx-sec);font-style:italic;font-size:10px;text-align:center;padding:8px 0">Sin datos</div>'}
      </div>
    </div>
  </div>`;
}

function show(t){
  ['res','inf','ali','pres','pbg','fis','p135','pmun','con'].forEach(x => {
    document.getElementById('tab-'+x).classList.add('hidden');
    document.getElementById('tb-'+x).classList.remove('active');
  });
  document.getElementById('tab-'+t).classList.remove('hidden');
  document.getElementById('tb-'+t).classList.add('active');
  if(t==='res') buildResumen();
  if(t==='inf'){ buildInfRanks(); buildHeatGrid(); renderInfTable(); }
  if(t==='ali'){ buildAliKPIs(); buildAliRanks(); buildAliTable(); }
  if(t==='pres'){ setTimeout(() => { buildPresKPIs(); buildPresTable(); drawPresChart(); }, 30); }
  if(t==='pbg'){ setTimeout(buildPBG, 30); }
  if(t==='fis'){ setTimeout(() => { drawFisChart(); buildFisRanks(); renderFisTable(); }, 30); }
  if(t==='p135'){ setTimeout(buildP135, 30); }
  if(t==='pmun'){ buildPmun(); }
  if(t==='con'){ buildCon(); }
}

